# ── IQR-based outlier detection for all numeric columns ──────────────────────
numeric_cols = ['age', 'bmi', 'blood_pressure', 'cholesterol', 'glucose']

iqr_results = {}
for col in numeric_cols:
    s = df[col].dropna()
    Q1, Q3 = s.quantile(0.25), s.quantile(0.75)
    IQR = Q3 - Q1
    lo, hi = Q1 - 1.5 * IQR, Q3 + 1.5 * IQR
    outliers = s[(s < lo) | (s > hi)]
    iqr_results[col] = {
        'Q1': round(Q1, 2), 'Q3': round(Q3, 2), 'IQR': round(IQR, 2),
        'lower_fence': round(lo, 2), 'upper_fence': round(hi, 2),
        'outlier_count': len(outliers),
        'outlier_pct': round(len(outliers)/len(s)*100, 2),
        'outlier_values_sample': sorted(outliers.values)[:5]
    }

for col, r in iqr_results.items():
    print(f"\n{col}:")
    for k, v in r.items():
        print(f"  {k}: {v}")
